import{_ as a,o,c as t,a0 as s}from"./chunks/framework.Bogozrur.js";const u=JSON.parse('{"title":"About Codecora","description":"","frontmatter":{},"headers":[],"relativePath":"about.md","filePath":"about.md"}'),r={name:"about.md"};function n(i,e,l,c,p,d){return o(),t("div",null,[...e[0]||(e[0]=[s(`<h1 id="about-codecora" tabindex="-1">About Codecora <a class="header-anchor" href="#about-codecora" aria-label="Permalink to &quot;About Codecora&quot;">​</a></h1><p>Codecora builds open-source developer tools for the AI agent era.</p><h2 id="our-philosophy" tabindex="-1">Our Philosophy <a class="header-anchor" href="#our-philosophy" aria-label="Permalink to &quot;Our Philosophy&quot;">​</a></h2><p><strong>Local-first by default.</strong> Your data should stay on your machine. We build tools that work offline, require zero API keys, and never phone home.</p><p><strong>Minimal dependencies.</strong> Single binaries where possible. No Docker required. No database servers to manage. Download and run.</p><p><strong>Open source.</strong> All projects are released under permissive licenses (Apache 2.0 or MIT). Use them, fork them, ship them.</p><h2 id="the-ecosystem" tabindex="-1">The Ecosystem <a class="header-anchor" href="#the-ecosystem" aria-label="Permalink to &quot;The Ecosystem&quot;">​</a></h2><p>Our tools are designed to work together. Uteke provides the memory layer, Cora reviews the code, and TrapFall captures the errors — all sharing a common philosophy of privacy, simplicity, and local-first operation.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>codecoradev/</span></span>
<span class="line"><span>├── uteke/           ← Semantic memory engine (Rust)</span></span>
<span class="line"><span>├── cora-cli/        ← AI code review (Rust)</span></span>
<span class="line"><span>├── trapfall/        ← Error capture (Rust + SvelteKit)</span></span>
<span class="line"><span>└── cora-review-action/ ← GitHub Action for PR review</span></span></code></pre></div><h2 id="contact" tabindex="-1">Contact <a class="header-anchor" href="#contact" aria-label="Permalink to &quot;Contact&quot;">​</a></h2><ul><li><strong>GitHub:</strong> <a href="https://github.com/codecoradev" target="_blank" rel="noreferrer">github.com/codecoradev</a></li><li><strong>Issues:</strong> Open an issue on any repository</li></ul>`,11)])])}const m=a(r,[["render",n]]);export{u as __pageData,m as default};
